  --secondary: oklch(0.970 0.004 150);
  --secondary-foreground: oklch(0.205 0.008 150);
  --muted: oklch(0.970 0.004 150);
  --muted-foreground: oklch(0.556 0.012 150);
  --accent: oklch(0.970 0.004 150);
  --accent-foreground: oklch(0.205 0.008 150);
  --destructive: oklch(0.577 0.215 27);
